import React, { useState } from "react";
import InternshipModal from "../components/InternshipModal";
import { useAuth } from "../context/AuthContext";

export default function Internship() {
  const { currentUser } = useAuth();
  const [isModalOpen, setModalOpen] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);

  const handlePostClick = () => {
    setEditingInternship(null); // clear for new post
    setModalOpen(true);
  };

  const handleSaveInternship = (newInternship) => {
    // Call your backend API or state update here
    console.log("Saved Internship:", newInternship);
  };

  return (
    <div className="p-4">
      {(currentUser.role === "admin" || currentUser.role === "hr") && (
        <button
          onClick={handlePostClick}
          className="bg-green-600 text-white px-4 py-2 rounded mb-4"
        >
          Post Internship
        </button>
      )}

      {/* Your existing internship cards and logic here */}

      <InternshipModal
        isOpen={isModalOpen}
        onClose={() => setModalOpen(false)}
        onSave={handleSaveInternship}
        editingInternship={editingInternship}
      />
    </div>
  );
}
